/// <summary>
/// sales agreement line import
/// </summary>
public class ETG_Acu_SalesAgreementLineImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_SalesAgreementLineImport  salesAgreementLineimport;

    salesAgreementLineimport = ETG_Acu_SalesAgreementLineImport::construct();

    if (salesAgreementLineimport.prompt())
    {
        salesAgreementLineimport.runOperation();
    }
}

public static ETG_Acu_SalesAgreementLineImport construct()
{
    return new ETG_Acu_SalesAgreementLineImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    salesAgreementLineEntity    salesAgreementLine;
    SalesAgreementHeaderEntity  salesAgreementHeader;

    salesAgreementLine.SalesAgreementId                     = conpeek(_con, 1);

    select firstonly salesAgreementHeader
        where salesAgreementHeader.SalesAgreementId         == salesAgreementLine.SalesAgreementId;

    salesAgreementLine.LineNumber                           = conpeek(_con, 2);
    salesAgreementLine.CommitmentType                       = CommitmentType::ProductQuantity;
    salesAgreementLine.CommittedQuantity                    = conpeek(_con, 4);
    //salesAgreementLine.DefaultLedgerDimensionDisplayValue   = conpeek(_con, 5);
    salesAgreementLine.EffectiveDate                        = salesAgreementHeader.DefaultEffectiveDate;
    salesAgreementLine.ETG_OverDeliveryPct                  = conpeek(_con, 7);
    salesAgreementLine.ETG_PriceType                        = conpeek(_con, 8);
    salesAgreementLine.ETG_UnderDeliveryPct                 = conpeek(_con, 9);
    salesAgreementLine.ExpirationDate                       = str2Date(conpeek(_con, 10), 123);
    salesAgreementLine.InvoiceCustomerAccountNumber         = salesAgreementHeader.InvoiceCustomerAccountNumber;
    salesAgreementLine.ItemNumber                           = conpeek(_con, 12);
    salesAgreementLine.Price                                = conpeek(_con, 13);
    salesAgreementLine.ProductColorId                       = conpeek(_con, 14);
    salesAgreementLine.ProductConfigurationId               = conpeek(_con, 15);
    salesAgreementLine.ProductSizeId                        = conpeek(_con, 16);
    salesAgreementLine.ProductStyleId                       = conpeek(_con, 17);
    salesAgreementLine.SalesAgreementLegalEntityId          = curExt();
    salesAgreementLine.ShippingSiteId                       = conpeek(_con, 19);
    salesAgreementLine.ShippingWarehouseId                  = conpeek(_con, 20);
    salesAgreementLine.UnitSymbol                           = conpeek(_con, 21);

    // BusinessUnit (22)	Contract (23)	Department (24)	Intercompany (25)	Plant_Warehouse_Office (26)	Product_Service (27)	Trader_Employee (28)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    salesAgreementLine.DefaultLedgerDimensionDisplayValue  = conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 28) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 27) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23);

    if (salesAgreementLine.validateWrite())
    {
        salesAgreementLine.insert();
    }
    else
    {
        throw error("Error while inserting sales agreement line");
    }
}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = 'Import sales agreement line';

    return ret;
}
